SELECT chs.test_id, chs.vehicle_variant, chs.axle_config, chs.stop_distance_100_0_m, chs.gcwr_stop_distance_m, chs.regulatory_brake_pass, chs.fade_test_pass, chs.trailer_stability_pass, chs.grade_launch_pass,
       var.variant_id, var.tow_rating_kg, var.body_style, var.trim_level
